import collections

def solve_grid(grid_str):
    """
    Applies the transformation rule to a grid.

    Rule:
    1. If the shape (non-zero color C) encloses a region of 0s, fill that region with C.
    2. Otherwise, hollow out the shape, keeping only the boundary of C's adjacent to 0s.
    """
    grid = [[int(x) for x in row.split()] for row in grid_str.strip().split('\n')]
    if not grid:
        return ""

    rows, cols = len(grid), len(grid[0])
    color = 0
    for r in range(rows):
        for c in range(cols):
            if grid[r][c] != 0:
                color = grid[r][c]
                break
        if color != 0:
            break

    # Find all 0s connected to the border (the "outside")
    q = collections.deque()
    visited = [[False for _ in range(cols)] for _ in range(rows)]

    for r in range(rows):
        if grid[r][0] == 0 and not visited[r][0]:
            q.append((r, 0))
            visited[r][0] = True
        if grid[r][cols - 1] == 0 and not visited[r][cols - 1]:
            q.append((r, cols - 1))
            visited[r][cols - 1] = True
    for c in range(cols):
        if grid[0][c] == 0 and not visited[0][c]:
            q.append((0, c))
            visited[0][c] = True
        if grid[rows - 1][c] == 0 and not visited[rows - 1][c]:
            q.append((rows - 1, c))
            visited[rows - 1][c] = True

    while q:
        r, c = q.popleft()
        for dr, dc in [(0, 1), (0, -1), (1, 0), (-1, 0)]:
            nr, nc = r + dr, c + dc
            if 0 <= nr < rows and 0 <= nc < cols and \
               not visited[nr][nc] and grid[nr][nc] == 0:
                visited[nr][nc] = True
                q.append((nr, nc))

    # Check if there are any enclosed 0s
    has_enclosed_zeros = False
    for r in range(rows):
        for c in range(cols):
            if grid[r][c] == 0 and not visited[r][c]:
                has_enclosed_zeros = True
                break
        if has_enclosed_zeros:
            break

    output_grid = [row[:] for row in grid]

    if has_enclosed_zeros:
        # Fill case
        for r in range(rows):
            for c in range(cols):
                if grid[r][c] == 0 and not visited[r][c]:
                    output_grid[r][c] = color
    else:
        # Hollow case
        output_grid = [[0 for _ in range(cols)] for _ in range(rows)]
        for r in range(rows):
            for c in range(cols):
                if grid[r][c] == color:
                    is_boundary = False
                    for dr, dc in [(0, 1), (0, -1), (1, 0), (-1, 0)]:
                        nr, nc = r + dr, c + dc
                        if not (0 <= nr < rows and 0 <= nc < cols) or grid[nr][nc] == 0:
                            is_boundary = True
                            break
                    if is_boundary:
                        output_grid[r][c] = color

    return "\n".join([" ".join(map(str, row)) for row in output_grid])

